  "inlineSchema": "// rabbit-shop — Prisma Schema PRODUCTION\n// Provider : PostgreSQL — Neon\n// Utilisé via : npm run db:push:prod\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n  // directUrl = env(\"DIRECT_URL\") // décommentez si vous utilisez un pooler Neon (PgBouncer)\n}\n\n// ─── Lapin ────────────────────────────────────────────────────────────────────\n// Modèle \"fiche de race en stock\" — une fiche représente une race/portée avec\n// une quantité disponible (stock), pas un individu unique.\nmodel Rabbit {\n  id   String @id @default(cuid())\n  slug String @unique\n\n  // Identité\n  name        String // nom de la fiche/portée, ex: \"Bélier nain Fauve\"\n  breed       String // ex: \"Bélier nain\", \"Rex\"\n  color       String\n  gender      String // \"male\" | \"female\" | \"mixed\" (lot mixte)\n  birthDate   DateTime?\n  weight      Float? // kg\n  description String?\n\n  // Prix (à l'unité)\n  price     Float\n  priceNote String? // \"négociable\", \"incluant vaccins\", etc.\n\n  // Stock — quantité de lapins disponibles sur cette fiche\n  stock Int @default(0)\n\n  // Statut dérivé du stock, mais stocké pour permettre un forçage manuel admin\n  // available → stock > 0, réservable\n  // sold      → stock épuisé (0), grisé côté client\n  status String @default(\"available\") // \"available\" | \"sold\"\n\n  // Médias\n  photos RabbitPhoto[]\n\n  // Réservations\n  reservations Reservation[]\n\n  // Dates\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([status])\n  @@index([slug])\n  @@index([breed])\n}\n\n// ─── Photos ───────────────────────────────────────────────────────────────────\nmodel RabbitPhoto {\n  id       Int     @id @default(autoincrement())\n  rabbitId String\n  rabbit   Rabbit  @relation(fields: [rabbitId], references: [id], onDelete: Cascade)\n  url      String // URL Cloudinary (secure_url)\n  publicId String? // public_id Cloudinary — nécessaire pour la suppression\n  position Int     @default(0) // ordre d'affichage\n  isMain   Boolean @default(false) // photo principale = couverture\n}\n\n// ─── Réservation ──────────────────────────────────────────────────────────────\nmodel Reservation {\n  id String @id @default(cuid())\n\n  // Quel lapin (quelle fiche de race)\n  rabbitId String\n  rabbit   Rabbit @relation(fields: [rabbitId], references: [id])\n\n  // Quantité réservée sur cette commande — décomptée du stock immédiatement\n  quantity Int @default(1)\n\n  // Acheteur\n  firstName String\n  lastName  String\n  email     String\n  phone     String\n  message   String?\n\n  // Statut de la réservation\n  // pending   → soumise, stock déjà décompté\n  // confirmed → confirmée par le vendeur (WhatsApp / tel)\n  // cancelled → annulée, le stock réservé est restitué à la fiche\n  status String @default(\"pending\") // \"pending\" | \"confirmed\" | \"cancelled\"\n\n  // Coordonnées GPS client\n  latitude  Float?\n  longitude Float?\n\n  // Livraison — zone résolue automatiquement depuis lat/lng (cf lib/delivery.js)\n  // \"abidjan\" -> 2000 FCFA | \"azaguie\" -> 1000 FCFA | \"pays_profond\" -> 3000 FCFA\n  deliveryZone String?\n  deliveryFee  Float?\n\n  // Confirmation WhatsApp\n  confirmedAt DateTime?\n  note        String? // note interne du vendeur\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([rabbitId])\n  @@index([email])\n  @@index([status])\n}\n\n// ─── Analytics ─────────────────────────────────────────────────────────────────\nmodel VisitStats {\n  id       String @id @default(\"global\")\n  accepted Int    @default(0)\n  declined Int    @default(0)\n  total    Int    @default(0)\n}\n",
